INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", 102301, 401, 0.0, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24001, 2, 10046, 2, "アヤネ");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", 102301, 402, 2.21, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24002, 1, 10046, 2, "アヤネ");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", 102301, 403, 0.0, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24003, 2, 10046, 2, "アヤネ");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", 192201, 701, 1.99, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24004, 2, 10046, 1, "アサヒ");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", 192201, 702, 2.21, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24005, 1, 10046, 2, "アサヒ");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", 192201, 703, 3.33, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24006, 2, 10046, 1, "アサヒ");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", 192301, 801, 0.0, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24007, 2, 10046, 2, "部員３");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", 192301, 802, 2.68, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24008, 1, 10046, 2, "部員３");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", 192301, 803, 0.0, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24009, 2, 10046, 2, "部員３");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "やった！", 192501, 501, 0.0, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24010, 1, 10046, 1, "");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "勝ったよ！", 192501, 502, 0.0, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24011, 1, 10046, 1, "");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "いい調子！", 192501, 503, 0.0, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24012, 1, 10046, 1, "");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", 113501, 111, 5.33, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24013, 6, 10046, 2, "ミサト");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", 113501, 112, 6.85, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24014, 1, 10046, 2, "ミサト");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", 113501, 113, 3.0, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24015, 1, 10046, 2, "ミサト");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", 192401, 611, 6.11, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24016, 1, 10046, 2, "ダイチ");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", 192401, 612, 6.75, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24017, 1, 10046, 2, "ダイチ");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", 192401, 613, 0.0, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24018, 2, 10046, 2, "ダイチ");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", 113401, 211, 4.52, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24019, 2, 10046, 1, "ハツネ");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", 113401, 212, 3.89, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24020, 2, 10046, 1, "ハツネ");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", 113401, 213, 13.49, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24021, 1, 10046, 2, "ハツネ");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", 106501, 311, 3.17, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24022, 1, 10046, 2, "カヤ");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", 106501, 312, 4.42, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24023, 1, 10046, 2, "カヤ");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", 106501, 313, 2.89, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24024, 6, 10046, 1, "カヤ");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", 102301, 421, 3.71, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24025, 4, 10046, 3, "アヤネ");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", 192201, 721, 5.1, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24026, 2, 10046, 1, "アサヒ");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", 192301, 821, 4.34, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24027, 1, 10046, 3, "部員３");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (0.0, "いい勝負だったよ\nまたやろうね", 192501, 521, 0.0, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24028, 1, 10046, 1, "");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (-360.0, "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", 113501, 101, 5.62, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24029, 1, 10046, 2, "ミサト");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (-360.0, "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", 113501, 102, 9.58, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24030, 1, 10046, 2, "ミサト");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (-360.0, "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", 113501, 103, 0.0, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24031, 2, 10046, 2, "ミサト");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (-360.0, "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", 113501, 104, 9.13, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24032, 2, 10046, 1, "ミサト");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (-360.0, "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", 113501, 105, 8.27, 24, "2020/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24033, 1, 10046, 2, "ミサト");
